sp_widget.client_script:
api.controller=function($scope, $sce, $timeout) {
	var c = this;

	// ── Config ──────────────────────────────────────────────
	// For Ollama (local): 'http://localhost:11434/api/chat'
	// For OpenAI:         'https://api.openai.com/v1/chat/completions'
	// For a ServiceNow proxy: '/api/YOUR_SCOPE/llm_proxy/stream'
	var LLM_ENDPOINT = c.data.llmEndpoint || 'http://localhost:11434/api/chat';
	var MODEL        = c.data.llmModel    || 'llama3.2';
	var API_KEY      = c.data.apiKey      || '';  // populated from server

	var abortController = null;

	c.data.messages        = [];
	c.data.userInput       = '';
	c.data.isStreaming     = false;
	c.data.streamingStarted = false;

	// ── Send Message ─────────────────────────────────────────
	c.sendMessage = function() {
		var text = (c.data.userInput || '').trim();
		if (!text || c.data.isStreaming) return;

		c.data.messages.push({ role: 'user', content: text });
		c.data.userInput = '';
		c.data.isStreaming = true;
		c.data.streamingStarted = false;

		// Placeholder for assistant response
		var assistantMsg = { role: 'assistant', content: '', streaming: true };
		c.data.messages.push(assistantMsg);

		_scrollToBottom();
		_streamFromLLM(assistantMsg);
	};

	c.handleKeydown = function(evt) {
		if (evt.key === 'Enter' && !evt.shiftKey) {
			evt.preventDefault();
			c.sendMessage();
		}
	};

	c.stopStreaming = function() {
		if (abortController) abortController.abort();
	};

	// ── Core Streaming Logic ─────────────────────────────────
	function _streamFromLLM(targetMsg) {
		abortController = new AbortController();

		// Build messages array for the API
		var apiMessages = c.data.messages
		.filter(function(m) { return !m.streaming || m.content; })
		.map(function(m) { return { role: m.role, content: m.content }; });

		// ── Payload: adjust for your LLM provider ──
		var payload = _buildPayload(apiMessages);
		var headers  = { 'Content-Type': 'application/json' };
		if (API_KEY) headers['Authorization'] = 'Bearer ' + API_KEY;

		fetch(LLM_ENDPOINT, {
			method: 'POST',
			headers: headers,
			body: JSON.stringify(payload),
			signal: abortController.signal
		})
			.then(function(response) {
			if (!response.ok) throw new Error('HTTP ' + response.status);
			return _readStream(response.body.getReader(), targetMsg);
		})
			.then(function() {
			_finalizeMessage(targetMsg);
		})
			.catch(function(err) {
			if (err.name !== 'AbortError') {
				targetMsg.content += '\n\n⚠️ Error: ' + err.message;
			}
			_finalizeMessage(targetMsg);
		});
	}

	// ── Stream Reader ────────────────────────────────────────
	function _readStream(reader, targetMsg) {
		var decoder = new TextDecoder();
		var buffer  = '';

		function pump() {
			return reader.read().then(function(result) {
				if (result.done) return;

				buffer += decoder.decode(result.value, { stream: true });
				var lines = buffer.split('\n');
				buffer = lines.pop(); // keep incomplete line in buffer

				lines.forEach(function(line) {
					var token = _parseLine(line);
					if (token) {
						c.data.streamingStarted = true;
						targetMsg.content += token;
						// Render markdown-ish content safely
						targetMsg.html = $sce.trustAsHtml(_simpleMarkdown(targetMsg.content));
						$timeout(function() { _scrollToBottom(); }, 0);
					}
				});

				$scope.$apply(); // trigger AngularJS digest
				return pump();
			});
		}
		return pump();
	}

	// ── Parse SSE/NDJSON line (handles OpenAI & Ollama formats) ──
	function _parseLine(line) {
		line = line.trim();
		if (!line || line === 'data: [DONE]') return null;

		// OpenAI SSE format: "data: {...}"
		if (line.startsWith('data: ')) {
			try {
				var json = JSON.parse(line.slice(6));
				return (json.choices && json.choices[0].delta && json.choices[0].delta.content) || null;
			} catch(e) { return null; }
		}

		// Ollama NDJSON format: "{...}"
		try {
			var json = JSON.parse(line);
			if (json.done) return null;
			return (json.message && json.message.content) || json.response || null;
		} catch(e) { return null; }
	}

	// ── Build payload per provider ───────────────────────────
	function _buildPayload(messages) {
		// Ollama format
		if (LLM_ENDPOINT.indexOf('ollama') > -1 || LLM_ENDPOINT.indexOf('11434') > -1) {
			return { model: MODEL, messages: messages, stream: true };
		}
		// OpenAI-compatible format (OpenAI, Anthropic via proxy, etc.)
		return { model: MODEL, messages: messages, stream: true, max_tokens: 2048 };
	}

	function _finalizeMessage(msg) {
		msg.streaming = false;
		c.data.isStreaming = false;
		c.data.streamingStarted = false;
		$scope.$apply();
		_scrollToBottom();
	}

	function _scrollToBottom() {
		$timeout(function() {
			var el = document.querySelector('.chat-messages');
			if (el) el.scrollTop = el.scrollHeight;
		}, 50);
	}

	// ── Minimal Markdown renderer ────────────────────────────
	function _simpleMarkdown(text) {
		return text
			.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')
			.replace(/```([\s\S]*?)```/g, '<pre><code>$1</code></pre>')
			.replace(/`([^`]+)`/g, '<code>$1</code>')
			.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
			.replace(/\*(.+?)\*/g, '<em>$1</em>')
			.replace(/\n/g, '<br>');
	}
}

sp_widget.css:
.llm-chat-container {
  display: flex;
  flex-direction: column;
  height: 600px;
  font-family: "Segoe UI", sans-serif;
  border: 1px solid #e0e0e0;
  border-radius: 12px;
  overflow: hidden;
  background: #fff;
}

.chat-messages {
  flex: 1;
  overflow-y: auto;
  padding: 20px;
  display: flex;
  flex-direction: column;
  gap: 16px;
}

.message {
  display: flex;
  gap: 10px;
  align-items: flex-start;
}

.message.user { flex-direction: row-reverse; }

.avatar {
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: #f0f0f0;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 16px;
  flex-shrink: 0;
}

.bubble {
  max-width: 75%;
  padding: 12px 16px;
  border-radius: 16px;
  line-height: 1.5;
  font-size: 14px;
}

.message.user .bubble {
  background: #0070d2;
  color: #fff;
  border-bottom-right-radius: 4px;
}

.message.assistant .bubble {
  background: #f4f6f8;
  color: #1a1a1a;
  border-bottom-left-radius: 4px;
}

.bubble pre {
  background: #1e1e2e;
  color: #cdd6f4;
  padding: 12px;
  border-radius: 8px;
  overflow-x: auto;
  font-size: 12px;
  margin: 8px 0;
}

.bubble code { font-family: 'Consolas', monospace; }

.cursor {
  animation: blink 1s step-end infinite;
  color: #0070d2;
}

@keyframes blink { 50% { opacity: 0; } }

.thinking {
  display: flex;
  gap: 6px;
  padding: 12px 16px;
  background: #f4f6f8;
  border-radius: 16px;
  width: fit-content;
}

.thinking span {
  width: 8px; height: 8px;
  background: #999;
  border-radius: 50%;
  animation: bounce 1.2s ease-in-out infinite;
}
.thinking span:nth-child(2) { animation-delay: 0.2s; }
.thinking span:nth-child(3) { animation-delay: 0.4s; }

@keyframes bounce {
  0%, 80%, 100% { transform: translateY(0); }
  40%           { transform: translateY(-8px); }
}

.chat-input-area {
  display: flex;
  gap: 10px;
  padding: 16px;
  border-top: 1px solid #e0e0e0;
  background: #fafafa;
}

.chat-input-area textarea {
  flex: 1;
  padding: 10px 14px;
  border: 1px solid #ccc;
  border-radius: 8px;
  resize: none;
  font-size: 14px;
  font-family: inherit;
  outline: none;
  transition: border-color 0.2s;
}

.chat-input-area textarea:focus { border-color: #0070d2; }

.chat-input-area button {
  padding: 10px 20px;
  background: #0070d2;
  color: white;
  border: none;
  border-radius: 8px;
  cursor: pointer;
  font-size: 14px;
  font-weight: 600;
  transition: background 0.2s;
}

.chat-input-area button:hover:not(:disabled) { background: #005fb2; }
.chat-input-area button:disabled { background: #aaa; cursor: not-allowed; }

sp_widget.script:
(function() {
	// Securely pass config to the client — never hardcode keys in HTML
	data.llmEndpoint ='https://ollama.solidprints.in/api/chat';
	data.llmModel    = 'gpt-oss:20b-cloud';

	// For API keys — use an encrypted system property
	// gs.getProperty reads 'Password2' type props safely
	data.apiKey = '967cac420466409583dfc46d374dcf11.9uB48_Ei_2m0cCNj4zz6yImA';
})();
